-- Owner chain for seeded appointment workspace:
-- medical/interpreter-heavy appointments go to Olga as operational owner,
-- concierge appointments go to Hans.
UPDATE appointments
SET owner_user_id = 'a0000000-0000-0000-0000-000000000004'::uuid
WHERE id IN (
    '11000000-0000-0000-0000-000000000001'::uuid,
    '11000000-0000-0000-0000-000000000002'::uuid,
    '11000000-0000-0000-0000-000000000003'::uuid,
    '11000000-0000-0000-0000-000000000004'::uuid,
    '11000000-0000-0000-0000-000000000005'::uuid,
    '11000000-0000-0000-0000-000000000006'::uuid,
    '11000000-0000-0000-0000-000000000007'::uuid,
    '11000000-0000-0000-0000-000000000008'::uuid,
    '11000000-0000-0000-0000-000000000009'::uuid,
    '11000000-0000-0000-0000-000000000010'::uuid,
    '11000000-0000-0000-0000-000000000013'::uuid,
    '11000000-0000-0000-0000-000000000014'::uuid
);

UPDATE appointments
SET owner_user_id = 'a0000000-0000-0000-0000-000000000007'::uuid
WHERE id IN (
    '11000000-0000-0000-0000-000000000011'::uuid,
    '11000000-0000-0000-0000-000000000012'::uuid
);

-- Demo interpreter responses, so the appointment screen shows meaningful states.
UPDATE appointments
SET interpreter_response = CASE id
    WHEN '11000000-0000-0000-0000-000000000001'::uuid THEN 'accepted'
    WHEN '11000000-0000-0000-0000-000000000002'::uuid THEN 'accepted'
    WHEN '11000000-0000-0000-0000-000000000003'::uuid THEN 'pending'
    WHEN '11000000-0000-0000-0000-000000000004'::uuid THEN 'pending'
    WHEN '11000000-0000-0000-0000-000000000005'::uuid THEN 'discussion_requested'
    WHEN '11000000-0000-0000-0000-000000000006'::uuid THEN 'pending'
    WHEN '11000000-0000-0000-0000-000000000007'::uuid THEN 'accepted'
    WHEN '11000000-0000-0000-0000-000000000008'::uuid THEN 'accepted'
    WHEN '11000000-0000-0000-0000-000000000009'::uuid THEN 'accepted'
    WHEN '11000000-0000-0000-0000-000000000010'::uuid THEN 'pending'
    WHEN '11000000-0000-0000-0000-000000000013'::uuid THEN 'pending'
    WHEN '11000000-0000-0000-0000-000000000014'::uuid THEN 'accepted'
    ELSE interpreter_response
END
WHERE id IN (
    '11000000-0000-0000-0000-000000000001'::uuid,
    '11000000-0000-0000-0000-000000000002'::uuid,
    '11000000-0000-0000-0000-000000000003'::uuid,
    '11000000-0000-0000-0000-000000000004'::uuid,
    '11000000-0000-0000-0000-000000000005'::uuid,
    '11000000-0000-0000-0000-000000000006'::uuid,
    '11000000-0000-0000-0000-000000000007'::uuid,
    '11000000-0000-0000-0000-000000000008'::uuid,
    '11000000-0000-0000-0000-000000000009'::uuid,
    '11000000-0000-0000-0000-000000000010'::uuid,
    '11000000-0000-0000-0000-000000000013'::uuid,
    '11000000-0000-0000-0000-000000000014'::uuid
);
